script:
const content = document.getElementById('win-content-' + winObj.id);
content.innerHTML = '<div class=\'p-4 flex flex-col h-full bg-slate-900 text-white select-none\'><div class=\'flex justify-between items-center bg-black/40 border border-slate-800 rounded-lg p-3 mb-3 shrink-0\'><div class=\'text-center\'><div class=\'text-[10px] uppercase tracking-wider text-slate-400\'>CPS</div><div class=\'speed-cps text-xl font-bold font-mono text-cyan-400\'>0.00</div></div><div class=\'text-center\'><div class=\'text-[10px] uppercase tracking-wider text-slate-400\'>Combo</div><div class=\'speed-combo text-xl font-bold font-mono text-pink-500\'>0</div></div><div class=\'text-center\'><div class=\'text-[10px] uppercase tracking-wider text-slate-400\'>Time</div><div class=\'speed-time text-xl font-bold font-mono text-amber-400\'>10.0s</div></div></div><div class=\'flex-1 bg-black/60 rounded-xl border border-slate-800 relative overflow-hidden mb-3\'><canvas class=\'speed-canvas absolute inset-0 w-full h-full cursor-pointer bg-slate-950/20\'></canvas><div class=\'speed-overlay absolute inset-0 flex flex-col items-center justify-center bg-black/80 p-6 text-center space-y-4\'><h3 class=\'text-lg font-bold text-sky-400\'>⚡ 极客手速压力测试</h3><p class=\'text-xs text-slate-400 max-w-[280px]\'>测试你在极低延迟蜂鸣回馈下的瞬时爆发力与点击节奏感。完全兼容 iPad 触屏！</p><div class=\'flex space-x-2 shrink-0\'><button class=\'btn-mode-10 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-xs font-bold rounded border border-slate-700\'>10s 爆发</button><button class=\'btn-mode-30 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-xs font-bold rounded border border-slate-700\'>30s 狂飙</button><button class=\'btn-mode-box px-3 py-1.5 bg-pink-900/40 hover:bg-pink-900/60 text-xs font-bold rounded border border-pink-500/30 text-pink-400\'>节奏盲盒</button></div></div></div><div class=\'flex justify-between text-[11px] opacity-60 px-1 shrink-0\'><span class=\'speed-best-clicks\'>历史最高点击: 0 次</span><span class=\'speed-best-cps\'>历史最高 CPS: 0.00</span></div></div>';

const canvas = content.querySelector('.speed-canvas');
const ctx = canvas.getContext('2d');
const cpsText = content.querySelector('.speed-cps');
const comboText = content.querySelector('.speed-combo');
const timeText = content.querySelector('.speed-time');
const overlay = content.querySelector('.speed-overlay');
const bestClicksText = content.querySelector('.speed-best-clicks');
const bestCpsText = content.querySelector('.speed-best-cps');
const btn10 = content.querySelector('.btn-mode-10');
const btn30 = content.querySelector('.btn-mode-30');
const btnBox = content.querySelector('.btn-mode-box');

let clicks = 0;
let combo = 0;
let maxCombo = 0;
let timeTotal = 10;
let timeLeft = 10;
let isPlaying = false;
let mode = 10;
let clickTimestamps = [];
let cpsHistory = [];
let particles = [];
let target = { x: 150, y: 150, r: 35, color: '#00f2fe' };

// 垫片函数：修复了丢失的花括号 Bug
const triggerSound = (freq, type, duration) => {
  if (typeof playSystemSound === 'function') {
    playSystemSound(freq, type, duration);
  } else {
    try {
      const AudioCtx = window.AudioContext || window.webkitAudioContext;
      if (!AudioCtx) return;
      const audioCtx = new AudioCtx();
      const osc = audioCtx.createOscillator();
      const gain = audioCtx.createGain();
      osc.type = type || 'sine';
      osc.frequency.setValueAtTime(freq, audioCtx.currentTime);
      gain.gain.setValueAtTime(0.08, audioCtx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + duration);
      osc.connect(gain);
      gain.connect(audioCtx.destination);
      osc.start();
      osc.stop(audioCtx.currentTime + duration);
    } catch(e) {}
  }
};

// JROS 沙盒隔离：将高分榜绑定在当前窗口应用命名空间，防多开冲突
window.jros_speed_records = window.jros_speed_records || {};
const appRecordKey = winObj.id || 'default';
window.jros_speed_records[appRecordKey] = window.jros_speed_records[appRecordKey] || { bestClicks: 0, bestCps: 0 };

const updateBestDisplay = () => {
  bestClicksText.innerText = '历史最高点击: ' + window.jros_speed_records[appRecordKey].bestClicks + ' 次';
  bestCpsText.innerText = '历史最高 CPS: ' + window.jros_speed_records[appRecordKey].bestCps.toFixed(2);
};
updateBestDisplay();

const resizeCanvas = () => {
  if (!canvas.parentElement) return;
  canvas.width = canvas.parentElement.clientWidth;
  canvas.height = canvas.parentElement.clientHeight;
};
resizeCanvas();
winObj.onResizeCallback = resizeCanvas;

let gameLoop = null;
let timerInterval = null;

const spawnTarget = () => {
  const padding = 50;
  target.x = padding + Math.random() * (canvas.width - padding * 2);
  target.y = padding + Math.random() * (canvas.height - padding * 2);
  target.r = mode === 'box' ? 18 + Math.random() * 22 : 40;
  target.color = 'hsl(' + Math.floor(Math.random() * 360) + ', 85%, 60%)';
};

const spawnExplosion = (x, y, color) => {
  for (let i = 0; i < 15; i++) {
    particles.push({
      x: x,
      y: y,
      vx: (Math.random() - 0.5) * 6,
      vy: (Math.random() - 0.5) * 6,
      r: Math.random() * 3 + 1,
      alpha: 1,
      decay: 0.02 + Math.random() * 0.03,
      color: color
    });
  }
};

const startTest = (gameMode) => {
  clearInterval(gameLoop);
  clearInterval(timerInterval);

  overlay.classList.add('hidden');
  isPlaying = true;
  clicks = 0;
  combo = 0;
  maxCombo = 0;
  clickTimestamps = [];
  cpsHistory = [];
  particles = [];
  mode = gameMode;
  if (mode === 'box') {
    timeTotal = 15;
    timeLeft = 15;
  } else {
    timeTotal = mode;
    timeLeft = mode;
  }
  spawnTarget();
  triggerSound(600, 'triangle', 0.15);
  setTimeout(() => triggerSound(800, 'triangle', 0.15), 100);

  timerInterval = setInterval(() => {
    timeLeft = parseFloat((timeLeft - 0.1).toFixed(1));
    if (timeLeft <= 0) {
      endTest();
    } else {
      timeText.innerText = timeLeft.toFixed(1) + 's';
      const now = Date.now();
      clickTimestamps = clickTimestamps.filter(t => now - t < 1000);
      const currentCps = clickTimestamps.length;
      cpsHistory.push(currentCps);
      cpsText.innerText = currentCps.toFixed(2);
    }
  }, 100);

  gameLoop = setInterval(() => {
    ctx.fillStyle = 'rgba(10, 10, 16, 0.2)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    if (mode === 'box') {
      ctx.shadowBlur = 15;
      ctx.shadowColor = target.color;
      ctx.fillStyle = target.color;
      ctx.beginPath();
      ctx.arc(target.x, target.y, target.r, 0, Math.PI * 2);
      ctx.fill();
      ctx.shadowBlur = 0;
    } else {
      ctx.font = 'bold 13px sans-serif';
      ctx.fillStyle = 'rgba(0, 242, 254, 0.35)';
      ctx.textAlign = 'center';
      ctx.fillText('💡 在画布任意区域狂点进行压力测试', canvas.width / 2, canvas.height / 2);
    }

    for (let i = particles.length - 1; i >= 0; i--) {
      let p = particles[i];
      p.x += p.vx;
      p.y += p.vy;
      p.alpha -= p.decay;
      if (p.alpha <= 0) {
        particles.splice(i, 1);
      } else {
        ctx.fillStyle = p.color;
        ctx.globalAlpha = p.alpha;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fill();
        ctx.globalAlpha = 1;
      }
    }
  }, 1000 / 60);
};

const endTest = () => {
  isPlaying = false;
  clearInterval(gameLoop);
  clearInterval(timerInterval);
  triggerSound(300, 'sawtooth', 0.3);
  const finalCps = clicks / timeTotal;
  if (clicks > window.jros_speed_records[appRecordKey].bestClicks) window.jros_speed_records[appRecordKey].bestClicks = clicks;
  if (finalCps > window.jros_speed_records[appRecordKey].bestCps) window.jros_speed_records[appRecordKey].bestCps = finalCps;
  updateBestDisplay();

  ctx.clearRect(0, 0, canvas.width, canvas.height);
  ctx.fillStyle = 'rgba(10, 10, 16, 0.9)';
  ctx.fillRect(0, 0, canvas.width, canvas.height);
  ctx.font = 'bold 18px sans-serif';
  ctx.fillStyle = '#ff007f';
  ctx.textAlign = 'center';
  ctx.fillText('🏆 测试分析报告', canvas.width / 2, 40);
  ctx.font = '12px sans-serif';
  ctx.fillStyle = '#94a3b8';
  ctx.fillText('总点击数: ' + clicks + ' 次', canvas.width / 2, 80);
  ctx.fillText('最高连击 (Max Combo): ' + maxCombo, canvas.width / 2, 105);
  ctx.fillText('平均手速 (Avg CPS): ' + finalCps.toFixed(2) + ' clicks/s', canvas.width / 2, 130);
  ctx.fillText('--- 点击频率 (CPS) 变化折线图 ---', canvas.width / 2, 180);
  const chartY = 200;
  const chartH = 80;
  const chartW = canvas.width * 0.7;
  const chartX = (canvas.width - chartW) / 2;
  ctx.strokeStyle = 'rgba(255,255,255,0.1)';
  ctx.lineWidth = 1;
  ctx.strokeRect(chartX, chartY, chartW, chartH);
  if (cpsHistory.length > 1) {
    ctx.strokeStyle = '#00f2fe';
    ctx.lineWidth = 2;
    ctx.beginPath();
    const step = chartW / (cpsHistory.length - 1);
    const maxVal = Math.max(...cpsHistory, 5);
    for (let i = 0; i < cpsHistory.length; i++) {
      const x = chartX + i * step;
      const y = chartY + chartH - (cpsHistory[i] / maxVal) * chartH;
      if (i === 0) ctx.moveTo(x, y);
      else ctx.lineTo(x, y);
    }
    ctx.stroke();
  }
  timeText.innerText = '已结束';
  overlay.classList.remove('hidden');
};

btn10.onclick = () => startTest(10);
btn30.onclick = () => startTest(30);
btnBox.onclick = () => startTest('box');

const handlePointerDown = (e) => {
  if (!isPlaying) return;
  const rect = canvas.getBoundingClientRect();
  const clientX = e.clientX || e.touches?.[0]?.clientX;
  const clientY = e.clientY || e.touches?.[0]?.clientY;
  if (clientX === undefined || clientY === undefined) return;
  const x = clientX - rect.left;
  const y = clientY - rect.top;
  const now = Date.now();
  if (mode === 'box') {
    const dist = Math.hypot(x - target.x, y - target.y);
    if (dist <= target.r) {
      clicks++;
      combo++;
      maxCombo = Math.max(maxCombo, combo);
      clickTimestamps.push(now);
      spawnExplosion(x, y, target.color);
      spawnTarget();
      triggerSound(600 + combo * 20, 'sine', 0.08);
    } else {
      combo = 0;
      triggerSound(150, 'sawtooth', 0.1);
    }
  } else {
    clicks++;
    combo++;
    maxCombo = Math.max(maxCombo, combo);
    clickTimestamps.push(now);
    const randHue = Math.floor(Math.random() * 60) + 170;
    spawnExplosion(x, y, 'hsl(' + randHue + ', 100%, 60%)');
    triggerSound(500 + Math.min(600, combo * 15), 'sine', 0.06);
  }
  comboText.innerText = combo;
  e.preventDefault();
};

canvas.addEventListener('pointerdown', handlePointerDown);

winObj.onDestroy = () => {
  clearInterval(gameLoop);
  clearInterval(timerInterval);
  canvas.removeEventListener('pointerdown', handlePointerDown);
};
